import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.BZO4qERu.js";const g=JSON.parse('{"title":"騎砍2 | 2026 必裝 MOD 推薦與安裝教學","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/mod-recommendations.md","filePath":"bannerlord/mod-recommendations.md"}'),o={name:"bannerlord/mod-recommendations.md"};function n(s,t,l,i,h,c){return r(),e("div",null,[...t[0]||(t[0]=[d(`<h1 id="騎砍2-2026-必裝-mod-推薦與安裝教學" tabindex="-1">騎砍2 | 2026 必裝 MOD 推薦與安裝教學 <a class="header-anchor" href="#騎砍2-2026-必裝-mod-推薦與安裝教學" aria-label="Permalink to &quot;騎砍2 | 2026 必裝 MOD 推薦與安裝教學&quot;">​</a></h1><hr><h2 id="前言-原版很好玩-裝了-mod-更好玩" tabindex="-1">前言：原版很好玩，裝了 MOD 更好玩 <a class="header-anchor" href="#前言-原版很好玩-裝了-mod-更好玩" aria-label="Permalink to &quot;前言：原版很好玩，裝了 MOD 更好玩&quot;">​</a></h2><p>先說一個殘酷的事實：騎砍2雖然是神作，但有些地方真的很讓人抓狂。</p><ul><li>每次跟領主講話要等讀取畫面？</li><li>打完仗要一個一個手動升級士兵？</li><li>外交選項只有「宣戰」和「停戰」二選一？</li></ul><p>這就是 MOD 存在的意義。</p><p>這篇精選 <strong>必裝 MOD</strong>，從生活品質改善到大幅擴充功能都有。</p><blockquote><p>⚠️ <strong>安裝 MOD 前請備份存檔！MOD 衝突可能導致壞檔！</strong></p></blockquote><hr><h2 id="一、mod-安裝基礎教學" tabindex="-1">一、MOD 安裝基礎教學 <a class="header-anchor" href="#一、mod-安裝基礎教學" aria-label="Permalink to &quot;一、MOD 安裝基礎教學&quot;">​</a></h2><h3 id="_1-1-兩種安裝方式" tabindex="-1">1.1 兩種安裝方式 <a class="header-anchor" href="#_1-1-兩種安裝方式" aria-label="Permalink to &quot;1.1 兩種安裝方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>優點</th><th>缺點</th></tr></thead><tbody><tr><td><strong>Steam 工作坊</strong></td><td>一鍵訂閱、自動更新</td><td>MOD 數量較少</td></tr><tr><td><strong>Nexus Mods + Vortex</strong></td><td>MOD 最全、可手動管理版本</td><td>需要下載管理器和手動排序</td></tr></tbody></table><blockquote><p>🎯 新手推薦 Steam 工作坊。進階玩家推薦 Nexus Mods + Vortex。</p></blockquote><h3 id="_1-2-四個必裝前置-mod" tabindex="-1">1.2 四個必裝前置 MOD <a class="header-anchor" href="#_1-2-四個必裝前置-mod" aria-label="Permalink to &quot;1.2 四個必裝前置 MOD&quot;">​</a></h3><p>無論你用什麼方式裝 MOD，這四個先裝（它們是 80% MOD 的依賴庫）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">順序</th><th>MOD 名稱</th><th>作用</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td><strong>Harmony</strong></td><td>MOD 開發框架</td></tr><tr><td style="text-align:center;">2</td><td><strong>ButterLib</strong></td><td>擴展函數庫</td></tr><tr><td style="text-align:center;">3</td><td><strong>UIExtenderEx</strong></td><td>UI 自訂擴展</td></tr><tr><td style="text-align:center;">4</td><td><strong>Mod Configuration Menu (MCM)</strong></td><td>遊戲內調整 MOD 設定</td></tr></tbody></table><blockquote><p>⚠️ <strong>安裝順序不能亂！</strong> Harmony → ButterLib → UIExtenderEx → MCM，照這個順序裝。</p></blockquote><h3 id="_1-3-mod-排序規則" tabindex="-1">1.3 MOD 排序規則 <a class="header-anchor" href="#_1-3-mod-排序規則" aria-label="Permalink to &quot;1.3 MOD 排序規則&quot;">​</a></h3><p>在啟動器中，MOD 順序很重要：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[前置 MOD]         ← Harmony, ButterLib, UIExtenderEx, MCM</span></span>
<span class="line"><span>[大型系統 MOD]     ← Diplomacy, Realistic Battle Mod</span></span>
<span class="line"><span>[中型功能 MOD]     ← Improved Garrisons</span></span>
<span class="line"><span>[小型功能 MOD]     ← Distinguished Service</span></span>
<span class="line"><span>[畫質/UI MOD]     ← 放在最下面</span></span></code></pre></div><hr><h2 id="二、2026-必裝-mod-推薦" tabindex="-1">二、2026 必裝 MOD 推薦 <a class="header-anchor" href="#二、2026-必裝-mod-推薦" aria-label="Permalink to &quot;二、2026 必裝 MOD 推薦&quot;">​</a></h2><h3 id="🔴-必裝級-大幅提升遊戲體驗" tabindex="-1">🔴 必裝級：大幅提升遊戲體驗 <a class="header-anchor" href="#🔴-必裝級-大幅提升遊戲體驗" aria-label="Permalink to &quot;🔴 必裝級：大幅提升遊戲體驗&quot;">​</a></h3><table tabindex="0"><thead><tr><th>MOD</th><th>功能</th><th>為什麼必裝</th></tr></thead><tbody><tr><td><strong>Diplomacy</strong></td><td>外交系統全面強化</td><td>原版外交只有「宣戰」和「停戰」，這個加上了聯盟、互不侵犯條約、分封系統</td></tr><tr><td><strong>Improved Garrisons</strong></td><td>駐軍自動化管理</td><td>自動招兵、訓練、護送——後期管理十幾座城時省掉 80% 微操</td></tr><tr><td><strong>Governors Handle Issues</strong></td><td>總督自動處理事務</td><td>城鎮每天彈出的村民糾紛、幫派問題，總督自動解決</td></tr><tr><td><strong>Realistic Battle Mod</strong></td><td>戰鬥 AI + 物理重製</td><td>盔甲真的有用、AI 更聰明、不會無腦衝</td></tr></tbody></table><h3 id="🟡-推薦級-特定玩法必備" tabindex="-1">🟡 推薦級：特定玩法必備 <a class="header-anchor" href="#🟡-推薦級-特定玩法必備" aria-label="Permalink to &quot;🟡 推薦級：特定玩法必備&quot;">​</a></h3><table tabindex="0"><thead><tr><th>MOD</th><th>功能</th><th>適合誰</th></tr></thead><tbody><tr><td><strong>My Little Warband</strong></td><td>自訂兵種樹</td><td>想創建自己的兵種體系的玩家</td></tr><tr><td><strong>Distinguished Service</strong></td><td>士兵晉升同伴</td><td>小兵表現好自動變成可招募同伴</td></tr><tr><td><strong>RTS Camera</strong></td><td>即時戰略視角</td><td>喜歡全戰系列指揮感</td></tr><tr><td><strong>Open Source Armory</strong></td><td>大量新武器和裝備</td><td>原版裝備太少，這個加了幾百件</td></tr><tr><td><strong>Serve as Soldier</strong></td><td>扮演小兵</td><td>從基層做起，跟隨領主打仗</td></tr><tr><td><strong>Banner Kings</strong></td><td>文化/宗教/爵位系統</td><td>追求中世紀模擬深度</td></tr><tr><td><strong>Calradia Expanded</strong></td><td>新地圖+新城鎮</td><td>原版地圖玩膩了</td></tr></tbody></table><h3 id="🟢-便利-畫質類" tabindex="-1">🟢 便利/畫質類 <a class="header-anchor" href="#🟢-便利-畫質類" aria-label="Permalink to &quot;🟢 便利/畫質類&quot;">​</a></h3><table tabindex="0"><thead><tr><th>MOD</th><th>功能</th></tr></thead><tbody><tr><td><strong>Arena Overhaul</strong></td><td>競技場全面改版，更多模式</td></tr><tr><td><strong>Xorberax&#39;s Legacy</strong></td><td>斷肢系統、處決動畫</td></tr><tr><td><strong>Attribute Per Level</strong></td><td>每次升級多給屬性點</td></tr><tr><td><strong>Detailed Character Creation</strong></td><td>更詳細的角色外觀自訂</td></tr></tbody></table><hr><h2 id="三、新手-mod-懶人包" tabindex="-1">三、新手 MOD 懶人包 <a class="header-anchor" href="#三、新手-mod-懶人包" aria-label="Permalink to &quot;三、新手 MOD 懶人包&quot;">​</a></h2><p>不想研究太多？只裝這 4 個，遊戲體驗直接翻倍：</p><table tabindex="0"><thead><tr><th>MOD</th><th>裝上去的改變</th></tr></thead><tbody><tr><td><strong>Diplomacy</strong></td><td>外交不再只有宣戰/停戰，可以結盟、威脅</td></tr><tr><td><strong>Improved Garrisons</strong></td><td>城堡自動招兵訓練，不用手動補兵</td></tr><tr><td><strong>Governors Handle Issues</strong></td><td>不再被「村長抱怨狼群」轟炸</td></tr><tr><td><strong>Realistic Battle Mod</strong></td><td>盔甲真的擋傷害、AI 不會無腦衝</td></tr></tbody></table><blockquote><p>✅ 這四個 MOD 都不影響存檔，現有存檔直接裝，不用重開。</p></blockquote><hr><h2 id="四、常見問題" tabindex="-1">四、常見問題 <a class="header-anchor" href="#四、常見問題" aria-label="Permalink to &quot;四、常見問題&quot;">​</a></h2><h3 id="q-裝-mod-後遊戲崩潰怎麼辦" tabindex="-1">Q：裝 MOD 後遊戲崩潰怎麼辦？ <a class="header-anchor" href="#q-裝-mod-後遊戲崩潰怎麼辦" aria-label="Permalink to &quot;Q：裝 MOD 後遊戲崩潰怎麼辦？&quot;">​</a></h3><ol><li>檢查 MOD 版本是否對應遊戲版本</li><li>檢查前置 MOD 是否都裝了（Harmony 等四個）</li><li>檢查 MOD 排序（前置在最上面）</li><li>逐一關閉最近安裝的 MOD 排查</li></ol><h3 id="q-裝-mod-後存檔壞了" tabindex="-1">Q：裝 MOD 後存檔壞了？ <a class="header-anchor" href="#q-裝-mod-後存檔壞了" aria-label="Permalink to &quot;Q：裝 MOD 後存檔壞了？&quot;">​</a></h3><p>懶人包的四個 MOD 都<strong>相容現有存檔</strong>。但大型 MOD（如 Banner Kings、Calradia Expanded）通常需要開新檔。</p><h3 id="q-成就會被鎖嗎" tabindex="-1">Q：成就會被鎖嗎？ <a class="header-anchor" href="#q-成就會被鎖嗎" aria-label="Permalink to &quot;Q：成就會被鎖嗎？&quot;">​</a></h3><p>裝 MOD 後 Steam 成就會被禁用。如果在意成就，用 <strong>Achievement Unblocker</strong> MOD 解除限制。</p><hr><h2 id="結語-適量就好-別裝太多" tabindex="-1">結語：適量就好，別裝太多 <a class="header-anchor" href="#結語-適量就好-別裝太多" aria-label="Permalink to &quot;結語：適量就好，別裝太多&quot;">​</a></h2><p>MOD 是騎砍2長壽的祕密之一，但裝太多會有副作用：</p><ul><li>開遊戲要五分鐘</li><li>隨機崩潰（而且不知道是哪個 MOD 的問題）</li><li>存檔肥到幾 GB</li></ul><p><strong>建議：</strong> 裝 5-10 個真正需要的就好。生活品質 MOD 優先，內容 MOD 選你最想要的 2-3 個。</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li>裝好 MOD 之後從頭開始？→ <a href="./beginner-guide.html">騎砍2 | 新手求生指南</a></li><li>想體驗 MOD 加強後的戰鬥？→ <a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。MOD 推薦依據遊戲 v1.4.x 正式版相容性篩選。</li></ul>`,54)])])}const m=a(o,[["render",n]]);export{g as __pageData,m as default};
